SELECT CAST(year AS INT) AS year, CAST(month AS INT) AS month, origin, COALESCE(origincityname, origin) AS origin_city, COALESCE(originstatename, '') AS origin_state, dest, COALESCE(destcityname, dest) AS dest_city, COALESCE(deststatename, '') AS dest_state, CONCAT(origin, '-', dest) AS route, reporting_airline, CASE WHEN AVG(distance) < 500 THEN 'Short-haul (<500 mi)' WHEN AVG(distance) < 1500 THEN 'Medium-haul (500-1500 mi)' ELSE 'Long-haul (>1500 mi)' END AS distance_group, COUNT(*) AS total_flights, SUM(CASE WHEN cancelled = 0 AND diverted = 0 THEN 1 ELSE 0 END) AS operated_flights, ROUND(100.0 * SUM(CASE WHEN arrdelay <= 15 AND cancelled = 0 AND diverted = 0 THEN 1 ELSE 0 END) / NULLIF(SUM(CASE WHEN cancelled = 0 AND diverted = 0 THEN 1 ELSE 0 END), 0), 2) AS on_time_pct, ROUND(100.0 * SUM(CASE WHEN cancelled = 1 THEN 1 ELSE 0 END) / COUNT(*), 2) AS cancellation_rate, ROUND(AVG(CASE WHEN cancelled = 0 THEN depdelay END), 2) AS avg_dep_delay_min, ROUND(AVG(CASE WHEN cancelled = 0 THEN arrdelay END), 2) AS avg_arr_delay_min, ROUND(PERCENTILE_APPROX(CASE WHEN cancelled = 0 AND diverted = 0 THEN arrdelay END, 0.90), 2) AS p90_arr_delay_min, ROUND(AVG(CASE WHEN cancelled = 0 THEN airtime END), 2) AS avg_airtime_min, ROUND(AVG(CASE WHEN cancelled = 0 THEN distance END), 2) AS avg_distance_miles FROM silver_flights GROUP BY year, month, origin, origincityname, originstatename, dest, destcityname, deststatename, reporting_airline
